            max-width: 300px;
            line-height: 1.6;
        }

        .info h3 {
            margin-bottom: 10px;
            color: #667eea;
        }

        .instructions {
            position: absolute;
            top: 20px;
            right: 20px;
            color: rgba(255, 255, 255, 0.7);
            font-size: 12px;
            text-align: right;
            background: rgba(0, 0, 0, 0.5);
            padding: 15px;
            border-radius: 10px;
        }
    </style>
</head>
